import java.util.HashMap;

public class BankingApp {

    private HashMap<String, Double> accounts;

    public BankingApp() {
        accounts = new HashMap<>();
        accounts.put("savings", 1000.0);
        accounts.put("checking", 500.0);
    }

    public double checkBalance(String account) {
        return accounts.get(account);
    }

    public boolean processTransaction(String account, double amount) {
        if (accounts.containsKey(account) && accounts.get(account) >= amount) {
            accounts.put(account, accounts.get(account) - amount);
            return true;
        }
        return false;
    }
}